      <context-menu-item
        v-for="(item, i) in items"
        :key="i"
        v-bind="item"
        @click="handleItemClick"
      />
    </context-menu>
  </div>
</template>

<script>
import setContainerSvg from '@/public/icon/set_container.svg';
export default {
  data() {
    return {
      style: {
        height: '300px',
        lineHeight: '300px',
        width: '500px',
        background: '#999999',
        textAlign: 'center',
        userSelect: 'none',
      },
      show: false,
      coordinate: {
        x: 0,
        y: 0,
      },
      items: [
        {
          type: 'title',
          label: '标题',
        },
        {
          icon: setContainerSvg,
          type: 'item',
          value: '0',
          label: '选项 0',
        },
        {
          type: 'line',
        },
        {
          icon: setContainerSvg,
          type: 'item',
          value: '1',
          label: '选项 1',
        },
        {
          icon: setContainerSvg,
          type: 'item',
          value: '2',
          label: '选项 2 (不会关闭)',
          closeOnClick: false,
        },
      ],
    };
  },
  methods: {
    handleContextMenu(e) {
      this.coordinate.x = e.clientX;
      this.coordinate.y = e.clientY;
      this.show = true;
    },
    handleItemClick({ label, value }) {
      this.$message.info(`label: ${label}, value: ${value}`);
    },
  },
};
</script>
