    title-clickable
    :refresh-method="handleRefresh"
    :active-tool-item.sync="activeToolItem"
    :tool-items="toolItems"
    @titleClick="onTitleClick"
    @refresh="onRefresh"
    @command="onCommand"
  >
    卡片内容
  </CardBase>
</template>

<script>
export default {
  data() {
    return {
      activeToolItem: 'edit',
      toolItems: [
        { label: '编辑', command: 'edit' },
        { label: '删除', command: 'delete' },
      ],
    };
  },
  methods: {
    onTitleClick() {
      this.$message('标题被点击');
    },
    async handleRefresh() {
      await new Promise((resolve) => setTimeout(resolve, 1000));
      this.$message('刷新完成');
    },
    onRefresh() {
      this.$message('刷新事件触发');
    },
    onCommand(cmd) {
      this.$message(`cmd is:${cmd}`);
      if (cmd === 'edit') {
        this.$message('执行编辑操作');
      }
    },
  },
};
</script>
