## 基本使用

简化了代码，同时方便将原本私有的状态开放给外部控制

```vue
<template>
  <div>{{ _text }}</div>
</template>

<script>
import { sync } from '@lw/common/mixins';
export default {
  // 外部 <component-name :text.sync="text" />
  // 内部状态 _text 更新时会更新外部 text 属性值
  // 同时外部 text 更新时会更新内部 _text
  mixins: [sync({ propName: 'text', valueName: '_text' })],
  props: {
    text: {
      type: String,
      required: false,
      default: '',
    },
  },
  data() {
    return {
      _text: '',
    };
  },
};
</script>
```

## 基本使用

使用方法与 [sync-同步混入](/component/components-common/sync-同步混入.html) 完全一致，区别是使用 `v-model` 来进行传参

```vue
<template>
  <div>{{ _text }}</div>
</template>

<script>
import { vModel } from '@lw/common/mixins';
export default {
  // 外部 <component-name v-model="text" />
  // 内部状态 _text 更新时会更新外部 text 属性值
  // 同时外部 text 更新时会更新内部 _text
  mixins: [vModel({ propName: 'text', valueName: '_text' })],
  props: {
    text: {
      type: String,
      required: false,
      default: '',
    },
  },
  data() {
    return {
      _text: '',
    };
  },
};
</script>
```

## 使用

在应用入口处引入样式文件

```javascript
import '@lw/common/lib/index.css';
```

注册组件的三种选择，原则上**只使用一种**，以免不必要的问题发生

1. 全局注册全部组件

```javascript
import Vue from 'vue';
import ComponentsCommon from '@lw/common/components';

Vue.use(ComponentsCommon);
```

2. 全局注册部分组件

```javascript
import Vue from 'vue';
import { TableContainer } from '@lw/common/components';

Vue.use(TableContainer);
```

3. 在需要用到的地方局部注册

```vue
<template>
  <table-container-form></table-container-form>
</template>

<script>
import { TableContainerForm } from '@lw/common/components';
export default {
  components: {
    TableContainerForm,
  },
};
</script>
```

## 使用

跟饿了么无差别，仅仅更改了包名

```js
import Vue from 'vue';
// element-ui -> @lw/element-ui
import ElementUI from '@lw/element-ui';
// element-ui... -> @lw/element-ui...
import '@lw/element-ui/lib/theme-chalk/index.css';
import App from './App.vue';

Vue.use(ElementUI);

new Vue({
  el: '#app',
  render: (h) => h(App),
});
```

## 按需引入

- 首先，安装 `babel-plugin-component`（若`babel >= 6`，则安装 `babel-plugin-component@0`）

  ```shell
  pnpm add babel-plugin-component -D
  ```

- 然后修改 `.babelrc`，在 `plugins` 增加如下内容

  ```json
  {
    ...
    "plugins": [
      ...
      [
        "component",
        {
          "libraryName": "@lw/element-ui",
          "styleLibraryName": "theme-chalk"
        }
      ]
      ...
    ]
    ...
  }
  ```

- 接着引入你需要的组件

  ```js
  import Vue from 'vue';
  import { Button, Select } from 'element-ui';
  import App from './App.vue';

  Vue.component(Button.name, Button);
  Vue.component(Select.name, Select);
  /* 或
   * Vue.use(Button)
   * Vue.use(Select)
   */

  new Vue({
    el: '#app',
    render: (h) => h(App),
  });
  ```
